diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..ea4f6a31f19c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2262,10 +2262,48 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
     return CallInst::Create(F, {Op0, Z});
   }
-
+  // sub smin(X+1, Y), smin(X, Y) --> X < Y ? 1 : 0
+  // sub smin(X, Y), smin(X+1, Y) --> X < Y ? -1 : 0
+  // sub umin(X+1, Y), umin(X, Y) --> X < Y ? 1 : 0
+  // sub umin(X, Y), umin(X+1, Y) --> X < Y ? -1 : 0
+  const APInt *C;
+  Intrinsic::ID MinMaxID = MinMax->getIntrinsicID();
+  // Check: Op0 = smin/umin(X + C, Y), Op1 = smin/umin(X, Y)
+  if (match(Op0, m_OneUse(m_SMin(m_NSWAddLike(m_Value(X), m_APInt(C)),
+                                  m_Specific(Y)))) &&
+      MinMaxID == Intrinsic::smin &&
+      match(Op1, m_OneUse(m_SMin(m_Specific(X), m_Specific(Y))))) {
+    if (C->isOne()) {
+      Value *Cond = Builder.CreateICmpSLT(X, Y);
+      return SelectInst::Create(Cond, ConstantInt::get(Ty, 1),
+                                ConstantInt::getNullValue(Ty));
+    }
+    if (C->isAllOnes()) {
+      Value *Cond = Builder.CreateICmpSLT(X, Y);
+      return SelectInst::Create(Cond, ConstantInt::getNullValue(Ty),
+                                ConstantInt::get(Ty, -1));
+    }
+  }
+  if (match(Op0, m_OneUse(m_UMin(m_NUWAddLike(m_Value(X), m_APInt(C)),
+                                  m_Specific(Y)))) &&
+      MinMaxID == Intrinsic::umin &&
+      match(Op1, m_OneUse(m_UMin(m_Specific(X), m_Specific(Y))))) {
+    if (C->isOne()) {
+      Value *Cond = Builder.CreateICmpULT(X, Y);
+      return SelectInst::Create(Cond, ConstantInt::get(Ty, 1),
+                                ConstantInt::getNullValue(Ty));
+    }
+    if (C->isAllOnes()) {
+      Value *Cond = Builder.CreateICmpULT(X, Y);
+      return SelectInst::Create(Cond, ConstantInt::getNullValue(Ty),
+                                ConstantInt::get(Ty, -1));
+    }
+  }
   return nullptr;
 }

